## Implementation Details

### REST API Architecture

#### Server Lifecycle

**`ControlRuntime`** — Background runtime spawning dedicated Tokio thread:

```rust
pub struct ControlRuntime {
    shutdown: Arc<Notify>,
    thread: Option<JoinHandle<()>>,
}

impl ControlRuntime {
    pub fn launch(world: SharedWorld, config: ControlServerConfig) -> Result<Self> {
        let shutdown = Arc::new(Notify::new());
        let shutdown_clone = shutdown.clone();
        let handle = ControlHandle::new(world.clone());

        let thread = thread::Builder::new()
            .name("scriptbots-control".into())
            .spawn(move || {
                match tokio::runtime::Builder::new_multi_thread()
                    .thread_name("scriptbots-control-rt")
                    .enable_all()
                    .build()
                {
                    Ok(runtime) => runtime.block_on(async move {
                        if let Err(err) = run_control_servers(handle, config, shutdown_clone).await {
                            error!(?err, "control servers terminated with error");
                        }
                    }),
                    Err(err) => error!(?err, "failed to build Tokio runtime"),
                }
            })?;

        Ok(Self {
            shutdown,
            thread: Some(thread),
        })
    }

    pub fn shutdown(mut self) -> Result<()> {
        self.shutdown.notify_waiters();
        if let Some(handle) = self.thread.take() {
            handle.join().map_err(|err| anyhow!("control thread panicked: {err:?}"))?;
        }
        Ok(())
    }
}
```

**Environment configuration:**

```rust
impl ControlServerConfig {
    pub fn from_env() -> Self {
        let mut config = Self::default();

        if let Ok(addr) = env::var("SCRIPTBOTS_CONTROL_REST_ADDR") {
            match addr.parse::<SocketAddr>() {
                Ok(addr) => config.rest_address = addr,
                Err(err) => warn!(%addr, %err, "invalid address; using default"),
            }
        }

        if let Ok(path) = env::var("SCRIPTBOTS_CONTROL_SWAGGER_PATH") {
            config.swagger_path = sanitize_swagger_path(&path);
        }

        if let Ok(flag) = env::var("SCRIPTBOTS_CONTROL_REST_ENABLED") {
            config.rest_enabled = matches!(
                flag.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            );
        }

        config
    }
}
```

#### Axum Router

**Core endpoints:**

```rust
fn build_rest_router(handle: ControlHandle) -> Router {
    let state = RestState { handle };
    Router::new()
        .route("/api/config", get(get_config_handler).patch(patch_config_handler))
        .route("/api/knobs", get(list_knobs_handler))
        .route("/api/knobs/apply", post(apply_knobs_handler))
        .with_state(state)
}
```

**Handler implementations:**

```rust
async fn get_config_handler(
    State(state): State<RestState>,
) -> Result<Json<ConfigSnapshot>, RestError> {
    let snapshot = state.handle.snapshot()?;
    Ok(Json(snapshot))
}

async fn patch_config_handler(
    State(state): State<RestState>,
    Json(request): Json<ConfigPatchRequest>,
) -> Result<Json<ConfigSnapshot>, RestError> {
    let snapshot = state.handle.apply_patch(request.patch)?;
    Ok(Json(snapshot))
}

async fn list_knobs_handler(
    State(state): State<RestState>,
) -> Result<Json<Vec<KnobEntry>>, RestError> {
    let knobs = state.handle.list_knobs()?;
    Ok(Json(knobs))
}

async fn apply_knobs_handler(
    State(state): State<RestState>,
    Json(request): Json<KnobApplyRequest>,
) -> Result<Json<ConfigSnapshot>, RestError> {
    let snapshot = state.handle.apply_updates(&request.updates)?;
    Ok(Json(snapshot))
}
```

**Error handling:**

```rust
struct RestError(ControlError);

impl IntoResponse for RestError {
    fn into_response(self) -> Response {
        let (status, message) = match &self.0 {
            ControlError::Lock => (StatusCode::SERVICE_UNAVAILABLE, "world state locked"),
            ControlError::InvalidPatch(msg) => (StatusCode::BAD_REQUEST, msg.as_str()),
            ControlError::UnknownPath(path) => {
                let msg = format!("unknown configuration path: {path}");
                return (StatusCode::NOT_FOUND, msg).into_response();
            }
            ControlError::Serialization(msg) => (StatusCode::INTERNAL_SERVER_ERROR, msg.as_str()),
        };
        (status, message.to_string()).into_response()
    }
}
```

