### MCP Server Integration

#### Protocol Implementation

**Server struct:**

```rust
struct ScriptBotsMcpServer {
    handle: ControlHandle,
}

#[async_trait]
impl McpServer for ScriptBotsMcpServer {
    async fn handle_call_tool(&self, request: CallToolRequest) -> Result<CallToolResponse> {
        match request.name.as_str() {
            "read_config" => self.tool_read_config(request.arguments).await,
            "update_config" => self.tool_update_config(request.arguments).await,
            "list_knobs" => self.tool_list_knobs(request.arguments).await,
            "get_snapshot" => self.tool_get_snapshot(request.arguments).await,
            _ => Ok(CallToolResponse::error(format!(
                "unknown tool: {}",
                request.name
            ))),
        }
    }

    async fn handle_list_tools(&self, _: ListToolsRequest) -> Result<ListToolsResponse> {
        Ok(ListToolsResponse {
            tools: vec![
                Tool {
                    name: "read_config".into(),
                    description: "Retrieve the current configuration snapshot".into(),
                    input_schema: json!({ "type": "object", "properties": {} }),
                },
                Tool {
                    name: "update_config".into(),
                    description: "Apply a configuration patch".into(),
                    input_schema: json!({
                        "type": "object",
                        "properties": {
                            "patch": { "type": "object" }
                        },
                        "required": ["patch"]
                    }),
                },
                Tool {
                    name: "list_knobs".into(),
                    description: "Enumerate all configuration knobs".into(),
                    input_schema: json!({ "type": "object", "properties": {} }),
                },
                Tool {
                    name: "get_snapshot".into(),
                    description: "Retrieve full world state snapshot".into(),
                    input_schema: json!({ "type": "object", "properties": {} }),
                },
            ],
        })
    }
}
```

**Tool implementations:**

```rust
async fn tool_read_config(&self, _args: Option<Value>) -> Result<CallToolResponse> {
    match self.handle.snapshot() {
        Ok(snapshot) => Ok(CallToolResponse::success(vec![ContentBlock::Text(
            serde_json::to_string_pretty(&snapshot)?,
        )])),
        Err(err) => Ok(CallToolResponse::error(err.to_string())),
    }
}

async fn tool_update_config(&self, args: Option<Value>) -> Result<CallToolResponse> {
    let patch = args
        .and_then(|v| v.get("patch").cloned())
        .ok_or_else(|| anyhow!("missing 'patch' argument"))?;

    match self.handle.apply_patch(patch) {
        Ok(snapshot) => Ok(CallToolResponse::success(vec![ContentBlock::Text(format!(
            "Configuration updated (tick {})",
            snapshot.tick
        ))])),
        Err(err) => Ok(CallToolResponse::error(err.to_string())),
    }
}
```

**Stdio transport:**

```rust
async fn run_mcp_server(handle: ControlHandle) -> Result<()> {
    let server = ScriptBotsMcpServer { handle };
    let transport = StdioServerTransport::new();
    transport.run(server).await?;
    Ok(())
}
```

### CLI Tool and TUI Dashboard

#### Command Structure

**Clap-based CLI:**

```rust
#[derive(Parser, Debug)]
#[command(name = "scriptbots-control", version, about)]
struct Cli {
    #[arg(long, env = "SCRIPTBOTS_CONTROL_URL", default_value = "http://127.0.0.1:8080")]
    base_url: String,

    #[command(subcommand)]
    command: Command,
}

#[derive(Subcommand, Debug)]
enum Command {
    List,
    Get,
    Set { path: String, value: String },
    Patch { file: Option<PathBuf>, json: Vec<String> },
    Watch { interval_ms: u64 },
}
```

#### List Command

**Output formatting:**

```rust
async fn list_command(client: &Client, base_url: &str) -> Result<()> {
    let knobs: Vec<KnobEntry> = fetch_knobs(client, base_url).await?;
    knobs.sort_by(|a, b| a.path.cmp(&b.path));

    println!(
        "{:<54} {:<10} {}",
        "PATH".bold().cyan(),
        "TYPE".bold().cyan(),
        "VALUE".bold().cyan()
    );
    println!("{}", "-".repeat(96).dimmed());

    for entry in knobs {
        println!(
            "{:<54} {:<10} {}",
            entry.path.bold(),
            knob_kind_label(entry.kind).italic().blue(),
            value_to_string(&entry.value, 32)
        );
    }

    Ok(())
}
```

