#### Set Command

**JSON value parsing:**

```rust
async fn set_command(client: &Client, base_url: &str, path: String, raw_value: String) -> Result<()> {
    let value = parse_value(&raw_value)?;  // Try JSON parse, fallback to string
    let request = KnobApplyRequest {
        updates: vec![KnobUpdate { path: path.clone(), value: value.clone() }],
    };
    let snapshot = apply_updates(client, base_url, &request).await?;
    println!("{} {} => {}", "updated".green().bold(), path, value_to_string(&value, 48));
    Ok(())
}
```

**Usage:**

```bash
