```

#### Patch Command

**File or inline JSON:**

```rust
async fn patch_command(client: &Client, base_url: &str, file: Option<PathBuf>, inline: Vec<String>) -> Result<()> {
    let patch_value = if let Some(path) = file {
        let data = std::fs::read_to_string(&path)?;
        serde_json::from_str::<Value>(&data)?
    } else {
        let joined = inline.join(" ");
        serde_json::from_str::<Value>(&joined)?
    };

    let body = ConfigPatchRequest { patch: patch_value };
    let snapshot = apply_patch(client, base_url, &body).await?;
    println!("{}", "Configuration patch applied".green().bold());
    Ok(())
}
```

**Usage:**

```bash
scriptbots-control patch --file config.json
scriptbots-control patch '{"world_width": 2560, "world_height": 1440}'
```

#### Watch Mode (TUI Dashboard)

**Ratatui implementation:**

```rust
fn watch_blocking(client: Client, base_url: String, interval: Duration) -> Result<()> {
    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, Hide)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let handle = tokio::runtime::Handle::current();
    let mut previous: HashMap<String, Value> = HashMap::new();
    let mut last_refresh = Instant::now() - interval;

    loop {
        if last_refresh.elapsed() >= interval {
            match handle.block_on(fetch_knobs(&client, &base_url)) {
                Ok(entries) => {
                    let rows = build_rows(&entries, &previous);
                    previous = entries.into_iter().map(|e| (e.path, e.value)).collect();
                }
                Err(err) => { /* Display error in UI */ }
            }
            last_refresh = Instant::now();
        }

        terminal.draw(|frame| draw_watch(frame, &rows, error, interval))?;

        if event::poll(Duration::from_millis(100))? {
            if let Event::Key(key) = event::read()? {
                match key.code {
                    KeyCode::Char('q') | KeyCode::Esc => break,
                    KeyCode::Char('r') => last_refresh = Instant::now() - interval,
                    _ => {}
                }
            }
        }
    }

    Ok(())
}
```

**Change detection:**

```rust
fn build_rows(entries: &[KnobEntry], previous: &HashMap<String, Value>) -> Vec<WatchRow> {
    let mut rows = Vec::new();
    for entry in entries {
        let changed = previous
            .get(&entry.path)
            .map(|value| value != &entry.value)
            .unwrap_or(true);
        rows.push(WatchRow {
            path: entry.path.clone(),
            kind: entry.kind,
            value: entry.value.clone(),
            changed,
        });
    }
    rows.sort_by(|a, b| a.path.cmp(&b.path));
    rows
}
```

**Table rendering:**

```rust
fn draw_watch(frame: &mut Frame, rows: &[WatchRow], error: Option<&str>, interval: Duration) {
    let table_rows: Vec<Row> = rows
        .iter()
        .map(|row| {
            let style = if row.changed {
                Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD)
            } else {
                Style::default()
            };
            Row::new(vec![
                Span::styled(&row.path, style),
                Span::styled(knob_kind_label(row.kind), Style::default().fg(Color::Blue)),
                Span::styled(value_to_string(&row.value, 40), style),
            ])
        })
        .collect();

    let table = Table::new(table_rows)
        .header(Row::new(vec!["PATH", "TYPE", "VALUE"]))
        .widths(&[Constraint::Percentage(45), Constraint::Length(12), Constraint::Percentage(43)]);

    frame.render_widget(table, layout[1]);
}
```

**Usage:**

```bash
scriptbots-control watch --interval-ms 500
# Press 'q' to quit, 'r' to force refresh
```

### Advanced Analytics System

#### Behavior Metrics

**Signal summarization:**

```rust
fn summarize_signal(values: &[f32]) -> (f64, f64, f64) {
    if values.is_empty() {
        return (0.0, 0.0, 0.0);
    }

    let len = values.len() as f64;
    let mut sum = 0.0;
    let mut max = 0.0f32;
    let mut positive_sum = 0.0;

    for &value in values {
        sum += f64::from(value);
        max = max.max(value.abs());
        positive_sum += f64::from(value.abs());
    }

    let mean = sum / len;
    let peak = max as f64;

    if positive_sum <= f64::EPSILON {
        return (mean, peak, 0.0);
    }

    // Shannon entropy of signal distribution
    let mut entropy = 0.0;
    for &value in values {
        let weight = value.abs() as f64 / positive_sum;
        if weight > 0.0 {
            entropy -= weight * weight.ln();
        }
    }

    (mean, peak, entropy)
}
```

