#### Food Grid Summary

**Statistical aggregation:**

```rust
fn summarize_food_grid(cells: &[f32]) -> Option<(f64, f64, f64, f32)> {
    if cells.is_empty() {
        return None;
    }

    let mut sum = 0.0;
    let mut sum_sq = 0.0;
    let mut max = f32::MIN;

    for &value in cells {
        let v = f64::from(value);
        sum += v;
        sum_sq += v * v;
        max = max.max(value);
    }

    let count = cells.len() as f64;
    let mean = sum / count;
    let variance = if count > 1.0 {
        (sum_sq - sum * mean) / (count - 1.0)
    } else {
        0.0
    };

    Some((sum, mean, variance.max(0.0), max))
}
```

**Usage:**

```rust
if macro_enabled {
    if let Some((total, avg, variance, peak)) = summarize_food_grid(self.food.cells()) {
        metrics.push(MetricSample::new("food.total", total));
