**Insertion:**

```rust
fn insert_births(tx: &Transaction<'_>, rows: &[BirthRow]) -> Result<(), duckdb::Error> {
    let mut stmt = tx.prepare(
        "insert or replace into births (
            tick, agent_id, parent_a, parent_b, brain_kind, brain_key,
            herbivore_tendency, generation, position_x, position_y, is_hybrid
        ) values (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
    )?;
    for row in rows {
        stmt.execute(params![
            row.tick, row.agent_id, row.parent_a, row.parent_b,
            row.brain_kind, row.brain_key, row.herbivore_tendency,
            row.generation, row.position_x, row.position_y, row.is_hybrid,
        ])?;
    }
    Ok(())
}
