+    for entry in entries {
+        let changed = previous
+            .get(&entry.path)
+            .map(|value| value != &entry.value)
+            .unwrap_or(true);
+        rows.push(WatchRow {
+            path: entry.path.clone(),
+            kind: entry.kind,
+            value: entry.value.clone(),
+            changed,
+        });
+    }
+    rows.sort_by(|a, b| a.path.cmp(&b.path));
+    rows
+}
