+impl Drop for ControlRuntime {
+    fn drop(&mut self) {
+        self.shutdown.notify_waiters();
+        if let Some(handle) = self.thread.take() {
+            if let Err(err) = handle.join() {
+                error!(?err, "control runtime thread panicked during drop");
+            }
+        }
+    }
