+fn summarize_signal(values: &[f32]) -> (f64, f64, f64) {
+    if values.is_empty() {
+        return (0.0, 0.0, 0.0);
+    }
+    let len = values.len() as f64;
+    let mut sum = 0.0f64;
+    let mut max = 0.0f32;
+    let mut positive_sum = 0.0f64;
+    for &value in values {
+        let v = f64::from(value);
+        sum += v;
+        let magnitude = value.abs();
+        if magnitude > max {
+            max = magnitude;
+        }
+        if value > 0.0 {
+            positive_sum += f64::from(value);
+        } else if value < 0.0 {
+            positive_sum += f64::from(-value);
+        }
+    }
+    let mean = sum / len;
+    let peak = max as f64;
+
+    if positive_sum <= f64::EPSILON {
+        return (mean, peak, 0.0);
+    }
+
+    let mut entropy = 0.0f64;
+    for &value in values {
+        let weight = value.abs() as f64 / positive_sum;
+        if weight > 0.0 {
+            entropy -= weight * weight.ln();
+        }
+    }
+    (mean, peak, entropy)
+}
+
+fn sanitize_metric_key(label: &str) -> String {
+    let mut result = String::with_capacity(label.len());
+    for ch in label.chars() {
+        if ch.is_ascii_alphanumeric() {
+            result.push(ch.to_ascii_lowercase());
+        } else {
+            result.push('_');
+        }
+    }
+    result
+}
+
+fn summarize_food_grid(cells: &[f32]) -> Option<(f64, f64, f64, f32)> {
+    if cells.is_empty() {
+        return None;
+    }
+    let mut sum = 0.0f64;
+    let mut sum_sq = 0.0f64;
+    let mut max = f32::MIN;
+    for &value in cells {
+        let v = f64::from(value);
+        sum += v;
+        sum_sq += v * v;
+        if value > max {
+            max = value;
+        }
+    }
+    let count = cells.len() as f64;
+    let mean = sum / count;
+    let variance = if count > 1.0 {
+        (sum_sq - sum * mean) / (count - 1.0)
+    } else {
+        0.0
+    };
+    Some((sum, mean, variance.max(0.0), max))
+}
